$router->get('/', function(){ Auth::check()?redirect('/feed'):redirect('/login'); });


$router->get('/robots.txt', function(){
    header('Content-Type: text/plain; charset=utf-8');
    $allow=setting('search_indexing','0')==='1';
    echo $allow?"User-agent: *\nAllow: /\nSitemap: ".app_url('/sitemap.xml')."\n":"User-agent: *\nDisallow: /\n";
    exit;
});

$router->get('/sitemap.xml', function(){
    if(setting('search_indexing','0')!=='1')abort(404,'Карта сайта отключена.');
    header('Content-Type: application/xml; charset=utf-8');
    $urls=[['loc'=>app_url('/'),'lastmod'=>date('Y-m-d')]];
    try{
        $users=DB::all("SELECT u.username,u.updated_at FROM users u LEFT JOIN user_settings s ON s.user_id=u.id AND s.`key`='profile_visibility' WHERE u.is_active=1 AND u.approval_status='approved' AND u.username IS NOT NULL AND COALESCE(s.`value`,'users')='everyone' ORDER BY u.id");
        foreach($users as $user)$urls[]=['loc'=>user_public_url((string)$user['username']),'lastmod'=>substr((string)($user['updated_at']??''),0,10)];
        $posts=DB::all("SELECT p.id,p.updated_at,u.username FROM profile_posts p JOIN users u ON u.id=p.user_id LEFT JOIN user_settings s ON s.user_id=u.id AND s.`key`='profile_visibility' WHERE p.deleted_at IS NULL AND p.status='published' AND p.visibility='everyone' AND COALESCE(s.`value`,'users')='everyone' ORDER BY p.id DESC LIMIT 5000");
        foreach($posts as $post)$urls[]=['loc'=>wall_post_public_url((string)$post['username'],(int)$post['id']),'lastmod'=>substr((string)($post['updated_at']??''),0,10)];
    }catch(Throwable $e){log_error($e);}
    echo '<?xml version="1.0" encoding="UTF-8"?>'."\n".'<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">';
    foreach($urls as $item){echo '<url><loc>'.htmlspecialchars((string)$item['loc'],ENT_XML1|ENT_QUOTES,'UTF-8').'</loc>';if(!empty($item['lastmod']))echo '<lastmod>'.htmlspecialchars((string)$item['lastmod'],ENT_XML1|ENT_QUOTES,'UTF-8').'</lastmod>';echo '</url>';}
    echo '</urlset>';exit;
});

$router->get('/brand/{kind}', function($params){
    $kind=(string)$params['kind'];$key=$kind==='favicon'?'favicon_path':'logo_path';$path=(string)setting($key,'');
    if($path===''||!str_starts_with($path,'branding/')){if($kind==='logo')brand_fallback_svg();abort(404,'Файл бренда не найден.');}
    $file=BASE_PATH.'/storage/uploads/'.$path;if(!is_file($file)){if($kind==='logo')brand_fallback_svg();abort(404,'Файл бренда не найден.');}
    if($kind==='logo'&&!logo_image_is_meaningful($file))brand_fallback_svg();
    $mime=(new finfo(FILEINFO_MIME_TYPE))->file($file)?:'image/png';header('Content-Type: '.$mime);header('Content-Length: '.filesize($file));$etag='"'.hash_file('sha256',$file).'"';header('Cache-Control: public, max-age=31536000, immutable');header('ETag: '.$etag);header('Last-Modified: '.gmdate('D, d M Y H:i:s',filemtime($file)).' GMT');if(trim((string)($_SERVER['HTTP_IF_NONE_MATCH']??''))===$etag){http_response_code(304);exit;}readfile($file);exit;
});

$router->get('/login', function(){
    if(Auth::check())redirect('/feed');
    View::render('login',['title'=>'Вход']);
});

$router->post('/login', function(){
    Csrf::validate();$login=trim((string)($_POST['login']??''));$password=(string)($_POST['password']??'');auth_rate_check($login);
    if(!Auth::attempt($login,$password)){
        auth_rate_fail($login);usleep(random_int(250000,520000));
        $_SESSION['flash_error']='Неверный логин, пароль или учётная запись пока недоступна.';redirect('/login');
    }
    auth_rate_success($login);redirect('/feed');
});

$router->post('/logout', function(){ Csrf::validate();Auth::logout();redirect('/login'); });

$router->get('/register', function(){
    if(Auth::check())redirect('/feed');$mode=registration_mode();if($mode==='closed')abort(404,'Регистрация сейчас закрыта.');
    View::render('register',['title'=>'Регистрация','registered'=>false,'registrationMode'=>$mode,'captcha'=>registration_captcha_prepare()]);
});

$router->post('/register', function(){
    $mode=registration_mode();if($mode==='closed')abort(403,'Регистрация сейчас закрыта.');Csrf::validate();
    $email=mb_lower(trim((string)($_POST['email']??'')));registration_rate_check($email);
    if(!registration_captcha_validate($_POST)){registration_rate_fail($email);abort(422,'Проверка защиты не пройдена. Обновите страницу и повторите.');}
    $username=normalize_username((string)($_POST['username']??''));$first=trim((string)($_POST['first_name']??''));$last=trim((string)($_POST['last_name']??''));$password=(string)($_POST['password']??'');$confirm=(string)($_POST['password_confirmation']??'');
    if(!filter_var($email,FILTER_VALIDATE_EMAIL)||$first===''||$last===''||strlen($password)<10||!hash_equals($password,$confirm))abort(422,'Проверьте имя, фамилию, email и совпадение паролей от 10 символов.');
    if(!valid_username($username))abort(422,'Ник обязателен: 3–40 латинских букв, цифр или подчёркиваний.');if(DB::one('SELECT id FROM users WHERE email=? OR username=? LIMIT 1',[$email,$username]))abort(422,'Такой email или ник уже зарегистрирован.');
    $display=trim($first.' '.$last);$auto=$mode==='email_auto';
    if($auto)$id=DB::insert("INSERT INTO users (email,username,first_name,last_name,display_name,password_hash,role,is_active,approval_status,approved_at,created_at,updated_at) VALUES (?,?,?,?,?,?,'user',1,'approved',CURRENT_TIMESTAMP,CURRENT_TIMESTAMP,CURRENT_TIMESTAMP)",[$email,$username,$first,$last,$display,password_hash_secure($password)]);
    else $id=DB::insert("INSERT INTO users (email,username,first_name,last_name,display_name,password_hash,role,is_active,approval_status,approved_at,created_at,updated_at) VALUES (?,?,?,?,?,?,'user',0,'pending',NULL,CURRENT_TIMESTAMP,CURRENT_TIMESTAMP)",[$email,$username,$first,$last,$display,password_hash_secure($password)]);
    foreach(['theme'=>'dark','notifications_enabled'=>'1','notification_sound'=>'1','notification_preview'=>'full','notification_avatar'=>'1','notification_max'=>'3','desktop_notifications'=>'0','wall_post_policy'=>'colleagues','profile_right_column'=>'1'] as $key=>$value)set_user_setting($key,$value,$id);
    registration_rate_success($email);audit($auto?'registration.auto':'registration.request','user',$id);queue_webhook($auto?'user.created':'user.registration_requested',['user_id'=>$id,'email'=>$email,'display_name'=>$display]);
    if($auto){auto_add_new_user_to_primary_admin($id);$_SESSION['flash_success']='Аккаунт создан. Теперь войдите.';redirect('/login');}
    admin_notify('registration','Новая заявка на регистрацию',$display.' · '.$email,app_url('/admin?section=users&user='.$id),$id);View::render('register',['title'=>'Регистрация отправлена','registered'=>true,'registrationMode'=>$mode,'captcha'=>[]]);
});

$router->get('/weather', function(){
    Auth::requireLogin();$weatherUserId=max(1,(int)($_GET['user']??Auth::id()));$profile=DB::one("SELECT id,display_name,username FROM users WHERE id=? AND is_active=1 AND approval_status='approved'",[$weatherUserId]);if(!$profile||!can_view_profile($profile,Auth::id()))abort(404,'Профиль недоступен.');$city=trim((string)raw_user_setting($weatherUserId,'weather_city',''));
    if($city===''){if($weatherUserId===Auth::id()){$_SESSION['flash_error']='Сначала укажите город в настройках оформления.';redirect('/settings/appearance');}abort(404,'Пользователь не указал город.');}
    try{$forecast=weather_short_forecast($city,false);}catch(Throwable $e){$forecast=['place'=>['name'=>$city,'admin1'=>''],'current'=>[],'hourly'=>[],'daily'=>[],'error'=>$e->getMessage()];}
    $long=weather_long_forecast($city,false);$radar=weather_radar_metadata(false);
    View::render('weather',['title'=>'Погода · '.$profile['display_name'],'city'=>$city,'forecast'=>$forecast,'longForecast'=>$long,'radar'=>$radar,'weatherProfile'=>$profile]);
});
