$router->get('/feed', function(){
    Auth::requireLogin();$uid=Auth::id();$tab=(string)($_GET['tab']??'colleagues');if(!in_array($tab,['all','colleagues','mine'],true))$tab='colleagues';
    $where="p.deleted_at IS NULL";$params=[$uid];
    if($tab==='mine'){$where.=' AND p.author_id=?';$params[]=$uid;}
    else{$where.=" AND (p.author_id=? OR EXISTS(SELECT 1 FROM colleague_requests r WHERE ((r.requester_id=? AND r.recipient_id=p.author_id) OR (r.recipient_id=? AND r.requester_id=p.author_id)) AND r.status='accepted'))";$params[]=$uid;$params[]=$uid;$params[]=$uid;if($tab==='colleagues')$where.=' AND p.author_id<>'.(int)$uid;}
    $sql="SELECT p.*,a.display_name author_name,a.username author_username,a.avatar_path,a.is_verified,a.verification_label,t.display_name wall_name,t.username wall_username,(SELECT COUNT(*) FROM profile_post_likes l WHERE l.post_id=p.id) like_count,(SELECT COUNT(*) FROM profile_post_likes l WHERE l.post_id=p.id AND l.user_id=?) liked_by_me FROM profile_posts p JOIN users a ON a.id=p.author_id JOIN users t ON t.id=p.user_id WHERE $where ORDER BY p.id DESC LIMIT 240";
    $rows=DB::all($sql,$params);$rows=array_values(array_filter($rows,fn($row)=>profile_post_can_view($row,$uid)));$posts=enrich_profile_posts(array_slice($rows,0,80));$stories=story_feed_users($uid,30);
    View::render('feed',['title'=>'Лента','tab'=>$tab,'posts'=>$posts,'stories'=>$stories]);
});
$router->post('/feed/post', function(){
    Auth::requireLogin();Csrf::validate();$uid=Auth::id();$body=trim((string)($_POST['body']??''));$photos=$_FILES['photos']??null;$videos=$_FILES['videos']??null;$documents=$_FILES['documents']??null;$hasPhotos=$photos&&is_array($photos['name']??null)&&count(array_filter($photos['name']))>0;$hasVideos=$videos&&is_array($videos['name']??null)&&count(array_filter($videos['name']))>0;$hasDocuments=$documents&&is_array($documents['name']??null)&&count(array_filter($documents['name']))>0;if($body===''&&!$hasPhotos&&!$hasVideos&&!$hasDocuments)abort(422,'Добавьте текст или вложение.');
    try{$state=profile_post_state_from_request($uid,$uid);}catch(RuntimeException $e){abort(422,$e->getMessage());}
    $id=DB::insert('INSERT INTO profile_posts (user_id,author_id,body,visibility,status,publish_at,created_at,updated_at) VALUES (?,?,?,?,?,?,CURRENT_TIMESTAMP,CURRENT_TIMESTAMP)',[$uid,$uid,utf8_substr($body,0,5000),$state['visibility'],$state['status'],$state['publishAt']]);$stored=[];
    try{if($hasPhotos)$stored=array_merge($stored,save_wall_post_photos($photos,$id,$uid));if($hasVideos)$stored=array_merge($stored,save_wall_post_videos($videos,$id,$uid));if($hasDocuments)$stored=array_merge($stored,save_wall_post_documents($documents,$id,$uid));}catch(Throwable $e){delete_uploaded_relatives($stored);DB::run('DELETE FROM profile_posts WHERE id=?',[$id]);throw $e;}
    $message=$state['status']==='draft'?'Пост сохранён в черновиках.':($state['status']==='scheduled'?'Публикация запланирована.':'Запись опубликована.');audit('feed.post','profile_post',$id,['status'=>$state['status'],'visibility'=>$state['visibility']]);if($state['status']==='published'&&$state['visibility']!=='only_me')notify_social_audience($uid,'Новая запись',(Auth::user()['display_name']??'Пользователь').' опубликовал запись',wall_post_public_url((string)(Auth::user()['username']??''),$id),'social-post-'.$id);if(str_contains((string)($_SERVER['HTTP_ACCEPT']??''),'application/json')){$post=$state['status']==='published'?profile_post_for_render($id):null;json_response(['ok'=>true,'id'=>$id,'state'=>$state['status'],'message'=>$message,'html'=>$post?View::partial('feed-post',['post'=>$post]):'']);}$_SESSION['flash_success']=$message;redirect('/feed');
});
