$router->post('/profile', function(){
    Auth::requireLogin();Csrf::validate();$uid=Auth::id();
    $first=trim((string)($_POST['first_name']??''));$last=trim((string)($_POST['last_name']??''));$username=normalize_username((string)($_POST['username']??''));$email=mb_lower(trim((string)($_POST['email']??'')));$bio=trim((string)($_POST['bio']??''));$status=trim((string)($_POST['status_text']??''));$birthday=trim((string)($_POST['birthday']??''));if($birthday!==''&&!preg_match('/^\d{4}-\d{2}-\d{2}$/',$birthday))abort(422,'Проверьте дату рождения.');
    if($first===''||$last===''||!filter_var($email,FILTER_VALIDATE_EMAIL))abort(422,'Заполните имя, фамилию и корректный email.');
    if(!valid_username($username))abort(422,'Ник обязателен: 3–40 латинских букв, цифр или подчёркиваний.');
    $duplicate=DB::one('SELECT id FROM users WHERE id<>? AND (email=? OR (username IS NOT NULL AND username=?)) LIMIT 1',[$uid,$email,$username]);if($duplicate)abort(422,'Email или логин уже занят.');
    DB::run('UPDATE users SET first_name=?,last_name=?,display_name=?,username=?,email=?,bio=?,status_text=?,birthday=?,updated_at=CURRENT_TIMESTAMP WHERE id=?',[$first,$last,trim($first.' '.$last),$username,$email,utf8_substr($bio,0,1000),utf8_substr($status,0,190),$birthday?:null,$uid]);notify_social_audience($uid,'Профиль обновлён',trim($first.' '.$last).' обновил данные профиля',user_public_url($username),'social-profile-update-'.$uid);
    $password=(string)($_POST['new_password']??'');if($password!==''){if(strlen($password)<10)abort(422,'Новый пароль должен содержать минимум 10 символов.');DB::run('UPDATE users SET password_hash=? WHERE id=?',[password_hash_secure($password),$uid]);}
    audit('profile.update','user',$uid);$_SESSION['flash_success']='Профиль сохранён.';redirect('/settings/general');
});

$router->post('/profile/avatar', function(){
    Auth::requireLogin();Csrf::validate();$uid=Auth::id();$file=$_FILES['avatar']??null;$error=(int)($file['error']??UPLOAD_ERR_NO_FILE);
    $errors=[UPLOAD_ERR_INI_SIZE=>'Фотография больше лимита PHP upload_max_filesize.',UPLOAD_ERR_FORM_SIZE=>'Фотография больше разрешённого размера формы.',UPLOAD_ERR_PARTIAL=>'Фотография загрузилась не полностью. Повторите отправку.',UPLOAD_ERR_NO_FILE=>'Выберите фотографию.',UPLOAD_ERR_NO_TMP_DIR=>'На сервере отсутствует временная папка загрузки.',UPLOAD_ERR_CANT_WRITE=>'Сервер не смог записать загруженный файл.',UPLOAD_ERR_EXTENSION=>'Загрузка остановлена расширением PHP.'];
    if($error!==UPLOAD_ERR_OK)abort($error===UPLOAD_ERR_INI_SIZE?413:422,$errors[$error]??'Не удалось принять фотографию.');
    $tmp=(string)($file['tmp_name']??'');if($tmp===''||!is_file($tmp))abort(422,'Временный файл фотографии не найден. Повторите загрузку.');
    if((int)($file['size']??0)<=0)abort(422,'Загруженная фотография пуста.');if((int)$file['size']>12*1024*1024)abort(413,'Аватар должен быть не больше 12 МБ.');
    $result=optimize_uploaded_image($tmp,'avatars/'.$uid.'-'.bin2hex(random_bytes(8)),1200,1200,86);$stored=(string)$result['relative'];$dest=BASE_PATH.'/storage/uploads/'.$stored;if(!is_file($dest)||(int)filesize($dest)<64){@unlink($dest);abort(500,'Сервер не смог сохранить обработанную фотографию.');}
    DB::pdo()->beginTransaction();try{DB::run('UPDATE user_avatar_history SET is_current=0 WHERE user_id=?',[$uid]);DB::run('UPDATE users SET avatar_path=?,updated_at=CURRENT_TIMESTAMP WHERE id=?',[$stored,$uid]);DB::run('INSERT INTO user_avatar_history (user_id,stored_path,mime_type,file_size,is_current,created_at) VALUES (?,?,?,?,1,CURRENT_TIMESTAMP)',[$uid,$stored,$result['mime'],$result['size']]);DB::pdo()->commit();}catch(Throwable $e){if(DB::pdo()->inTransaction())DB::pdo()->rollBack();@unlink($dest);throw $e;}
    audit('profile.avatar','user',$uid);notify_social_audience($uid,'Новая фотография профиля',(Auth::user()['display_name']??'Пользователь').' обновил фотографию',user_public_url((string)(Auth::user()['username']??'')),'social-avatar-update-'.$uid,avatar_url($uid,$stored));
    $avatarUrl=avatar_url($uid,$stored);$wantsJson=str_contains(strtolower((string)($_SERVER['HTTP_ACCEPT']??'')),'application/json')||strtolower((string)($_SERVER['HTTP_X_REQUESTED_WITH']??''))==='xmlhttprequest';if($wantsJson)json_response(['ok'=>true,'avatar_url'=>$avatarUrl]);$_SESSION['flash_success']='Аватар обновлён.';redirect('/profile');
});
