$router->post('/profile/story', function(){
    Auth::requireLogin();Csrf::validate();
    $file=$_FILES['story']??null;$error=(int)($file['error']??UPLOAD_ERR_NO_FILE);
    $uploadErrors=[UPLOAD_ERR_INI_SIZE=>'Файл больше лимита PHP upload_max_filesize.',UPLOAD_ERR_FORM_SIZE=>'Файл больше разрешённого размера формы.',UPLOAD_ERR_PARTIAL=>'Файл загрузился не полностью. Повторите отправку.',UPLOAD_ERR_NO_FILE=>'Выберите фото или видео для истории.',UPLOAD_ERR_NO_TMP_DIR=>'На сервере отсутствует временная папка загрузки.',UPLOAD_ERR_CANT_WRITE=>'Сервер не смог записать загруженный файл.',UPLOAD_ERR_EXTENSION=>'Загрузка остановлена расширением PHP.'];
    if($error!==UPLOAD_ERR_OK)abort($error===UPLOAD_ERR_INI_SIZE?413:422,$uploadErrors[$error]??'Не удалось принять файл истории.');
    $tmp=(string)($file['tmp_name']??'');if($tmp===''||!is_file($tmp))abort(422,'Временный файл истории не найден. Повторите загрузку.');
    $max=min(40,max(1,(int)setting('max_upload_mb','25')))*1024*1024;$declared=(int)($file['size']??0);$actual=(int)filesize($tmp);$size=max($declared,$actual);if($size<1)abort(422,'Файл истории пустой.');if($size>$max)abort(413,'История должна быть не больше '.round($max/1024/1024).' МБ.');
