    $stickers=DB::all('SELECT s.id,s.name,s.mime_type,p.name pack_name FROM stickers s JOIN sticker_packs p ON p.id=s.pack_id WHERE s.is_active=1 AND p.is_active=1 ORDER BY p.name,s.sort_order,s.id LIMIT 300');
    View::render('messenger',compact('chats','chat','messages','members','stickers','currentMembership','cursor','invites','joinRequests','focusMessageId')+['title'=>setting('site_name','KOVCHEG CMS'),'permissions'=>user_permissions()]);
};


