$renderChannelPostPage=static function(int $chatId,int $messageId): void {
    Auth::requireLogin();$member=require_chat_member($chatId);$chat=DB::one("SELECT * FROM chats WHERE id=? AND type='channel' AND deleted_at IS NULL",[$chatId]);if(!$chat)abort(404,'Канал не найден.');$root=message_row($messageId);if(!$root||(int)$root['chat_id']!==$chatId||!empty($root['deleted_at']))abort(404,'Публикация не найдена.');
    if(!empty($root['thread_root_id'])){$messageId=(int)$root['thread_root_id'];$root=message_row($messageId);}elseif(!empty($root['reply_to_id'])){$candidate=DB::one('SELECT COALESCE(thread_root_id,reply_to_id) root_id FROM messages WHERE id=?',[$root['id']]);$messageId=(int)($candidate['root_id']??$root['reply_to_id']);$root=message_row($messageId);}if(!$root)abort(404,'Публикация не найдена.');
    $comments=DB::all('SELECT m.*,c.type chat_type,c.comments_enabled,c.reactions_enabled,c.sign_messages,u.display_name,u.first_name,u.last_name,u.username,u.avatar_path,u.is_verified,u.verification_label,fu.display_name forwarded_from_name,fu.username forwarded_from_username,fm.created_at forwarded_from_created_at,rm.body reply_body,ru.display_name reply_sender_name,a.id attachment_id,a.original_name,a.stored_path,a.mime_type,a.file_size,0 comments_count FROM messages m JOIN chats c ON c.id=m.chat_id JOIN users u ON u.id=m.sender_id LEFT JOIN messages fm ON fm.id=m.forwarded_from_id LEFT JOIN users fu ON fu.id=fm.sender_id LEFT JOIN messages rm ON rm.id=m.reply_to_id LEFT JOIN users ru ON ru.id=rm.sender_id LEFT JOIN attachments a ON a.message_id=m.id WHERE m.chat_id=? AND m.thread_root_id=? AND m.deleted_at IS NULL ORDER BY m.id ASC LIMIT 1000',[$chatId,$messageId]);
    $commentTree=channel_comment_tree($comments,$messageId);$root['comments_count']=count($comments);$stickers=DB::all('SELECT s.id,s.name,s.mime_type,p.name pack_name FROM stickers s JOIN sticker_packs p ON p.id=s.pack_id WHERE s.is_active=1 AND p.is_active=1 ORDER BY p.name,s.sort_order,s.id LIMIT 300');View::render('channel-post',['title'=>'Публикация · '.($chat['title']??'Канал'),'chat'=>$chat,'root'=>$root,'comments'=>$comments,'commentTree'=>$commentTree,'membership'=>$member,'stickers'=>$stickers]);
};
