$router->post('/ajax/sync', function(){
    Auth::requireLogin();Csrf::validate();$uid=Auth::id();$after=max(0,(int)($_POST['after_event']??0));$active=max(0,(int)($_POST['active_chat']??0));$activeThread=max(0,(int)($_POST['active_thread']??0));if($active)require_chat_member($active);if(session_status()===PHP_SESSION_ACTIVE)session_write_close();touch_presence($uid);try{DB::run("UPDATE push_deliveries SET status='consumed',consumed_at=CURRENT_TIMESTAMP,next_attempt_at=NULL WHERE user_id=? AND consumed_at IS NULL AND status IN ('pending','failed')",[$uid]);}catch(Throwable){}
    $events=DB::all('SELECT e.* FROM chat_events e JOIN chat_members cm ON cm.chat_id=e.chat_id AND cm.user_id=? JOIN chats c ON c.id=e.chat_id AND c.deleted_at IS NULL WHERE cm.is_hidden=0 AND e.id>? ORDER BY e.id ASC LIMIT 250',[$uid,$after]);
    $output=[];$notifications=[];$chatIds=[];$last=$after;$activeLast=0;
    foreach($events as $event){
        $last=max($last,(int)$event['id']);$chatId=(int)$event['chat_id'];$chatIds[$chatId]=true;$payload=json_decode((string)($event['payload_json']??''),true)?:[];
        $item=['id'=>(int)$event['id'],'type'=>$event['event_type'],'chat_id'=>$chatId,'message_id'=>$event['message_id']?(int)$event['message_id']:null,'root_id'=>(int)($payload['root_id']??0)];
        if($event['message_id']){
            $message=message_row((int)$event['message_id']);
            if($message){
                $item['sender_id']=(int)$message['sender_id'];$item['sender_name']=$message['display_name'];$item['sender_avatar']=avatar_url((int)$message['sender_id'],(string)($message['avatar_path']??''));$item['preview']=message_preview($message);
                $isComment=$event['event_type']==='comment.created'||(($message['chat_type']??'')==='channel'&&!empty($message['reply_to_id']));
                if($chatId===$active&&!$isComment&&$event['event_type']!=='message.deleted')$item['html']=View::partial('message',['m'=>$message]);
                if($isComment&&$activeThread&&(int)$message['reply_to_id']===$activeThread)$item['comment_html']=View::partial('message',['m'=>$message,'threadMode'=>true]);
                if($chatId===$active&&!$isComment&&$event['event_type']==='message.created')$activeLast=max($activeLast,(int)$message['id']);
                if(in_array($event['event_type'],['message.created','comment.created'],true)&&(int)$message['sender_id']!==$uid&&$chatId!==$active){
                    $chat=DB::one('SELECT * FROM chats WHERE id=?',[$chatId]);
                    $notifications[]=['event_id'=>(int)$event['id'],'chat_id'=>$chatId,'chat_title'=>$chat?chat_title($chat,$uid):'Переписка','sender_id'=>(int)$message['sender_id'],'sender_name'=>$message['display_name'],'avatar_url'=>avatar_url((int)$message['sender_id'],(string)($message['avatar_path']??'')),'text'=>($isComment?'Комментарий: ':'').message_preview($message),'message_id'=>(int)$message['id'],'root_id'=>(int)($message['reply_to_id']??0),'url'=>message_public_url($message,$uid)];
                }
            }
        }
        $output[]=$item;
    }
    if($active&&$activeLast)DB::run('UPDATE chat_members SET last_read_message_id=GREATEST(COALESCE(last_read_message_id,0),?) WHERE chat_id=? AND user_id=?',[$activeLast,$active,$uid]);
    $chatUpdates=[];
    foreach(array_keys($chatIds) as $chatId){
        $row=DB::one("SELECT c.id,c.type,c.title,c.username,c.avatar_path,cm.last_read_message_id,cm.cleared_before_message_id,cm.is_muted,cm.is_pinned,cm.is_archived,
        (SELECT id FROM messages m WHERE m.chat_id=c.id AND m.deleted_at IS NULL AND m.reply_to_id IS NULL AND m.id>COALESCE(cm.cleared_before_message_id,0) ORDER BY id DESC LIMIT 1) last_message_id,
        (SELECT body FROM messages m WHERE m.chat_id=c.id AND m.deleted_at IS NULL AND m.reply_to_id IS NULL AND m.id>COALESCE(cm.cleared_before_message_id,0) ORDER BY id DESC LIMIT 1) last_body,
        (SELECT type FROM messages m WHERE m.chat_id=c.id AND m.deleted_at IS NULL AND m.reply_to_id IS NULL AND m.id>COALESCE(cm.cleared_before_message_id,0) ORDER BY id DESC LIMIT 1) last_type,
        (SELECT created_at FROM messages m WHERE m.chat_id=c.id AND m.deleted_at IS NULL AND m.reply_to_id IS NULL AND m.id>COALESCE(cm.cleared_before_message_id,0) ORDER BY id DESC LIMIT 1) last_at,
        (SELECT COUNT(*) FROM messages m WHERE m.chat_id=c.id AND m.deleted_at IS NULL AND m.reply_to_id IS NULL AND m.id>GREATEST(COALESCE(cm.last_read_message_id,0),COALESCE(cm.cleared_before_message_id,0)) AND m.sender_id<>?) unread
        FROM chats c JOIN chat_members cm ON cm.chat_id=c.id WHERE c.id=? AND cm.user_id=? AND cm.is_hidden=0",[$uid,$chatId,$uid]);
        if($row){if($chatId===$active)$row['unread']=0;$row['display_title']=chat_title($row,$uid);if($row['last_type']==='sticker')$row['last_body']='Стикер';if($row['last_type']==='file')$row['last_body']='Вложение';$chatUpdates[]=$row;}
    }
    if($active)try{DB::run('UPDATE user_notifications SET is_read=1,read_at=COALESCE(read_at,CURRENT_TIMESTAMP) WHERE user_id=? AND tag=? AND is_read=0',[$uid,'chat-'.$active]);}catch(Throwable){}
    $notificationAfter=max(0,(int)($_POST['after_notification']??0));$bellItems=[];foreach(user_notifications($uid,40) as $note)if((int)$note['id']>$notificationAfter)$bellItems[]=$note;
    json_response(['ok'=>true,'events'=>$output,'notifications'=>$notifications,'chat_updates'=>$chatUpdates,'last_event'=>$last,'user_notifications'=>$bellItems,'user_unread'=>user_unread_count($uid),'message_unread'=>chat_unread_count($uid)]);
});

