$router->post('/ajax/chat/{id}/action', function($params){
    Auth::requireLogin();Csrf::validate();$id=(int)$params['id'];$member=chat_member($id);if(!$member)abort(404,'Переписка не найдена.');$chat=DB::one('SELECT * FROM chats WHERE id=? AND deleted_at IS NULL',[$id]);if(!$chat)abort(404,'Переписка не найдена.');$action=(string)($_POST['action']??'');
