    elseif($action==='archive')DB::run('UPDATE chat_members SET is_archived=1,is_pinned=0 WHERE chat_id=? AND user_id=?',[$id,Auth::id()]);
    elseif($action==='unarchive')DB::run('UPDATE chat_members SET is_archived=0 WHERE chat_id=? AND user_id=?',[$id,Auth::id()]);
    elseif($action==='clear'){$last=(int)(DB::one('SELECT COALESCE(MAX(id),0) c FROM messages WHERE chat_id=?',[$id])['c']??0);DB::run('UPDATE chat_members SET cleared_before_message_id=?,last_read_message_id=? WHERE chat_id=? AND user_id=?',[$last,$last,$id,Auth::id()]);}
    elseif($action==='delete'){
