$router->post('/admin/modules/install', function(){
    Auth::requireAdmin();Csrf::validate();
    $wantsJson=str_contains(strtolower((string)($_SERVER['HTTP_ACCEPT']??'')),'application/json')||strtolower((string)($_SERVER['HTTP_X_REQUESTED_WITH']??''))==='xmlhttprequest';
    $files=$_FILES['modules']??($_FILES['module']??null);if(!$files){if($wantsJson)json_response(['ok'=>false,'error'=>'Выберите ZIP-пакеты.'],422);abort(422,'Выберите ZIP-пакеты.');}
    if(!is_array($files['name']??null))$files=['name'=>[$files['name']??'module.zip'],'tmp_name'=>[$files['tmp_name']??''],'error'=>[$files['error']??UPLOAD_ERR_NO_FILE]];
    if($wantsJson&&session_status()===PHP_SESSION_ACTIVE)session_write_close();
    $results=[];$applyRequired=false;
    foreach($files['name'] as $i=>$name){
        if((int)($files['error'][$i]??UPLOAD_ERR_NO_FILE)!==UPLOAD_ERR_OK){$message='Ошибка загрузки файла.';$results[]=['ok'=>false,'file'=>(string)$name,'message'=>$message];admin_notify('error','Ошибка загрузки модуля',(string)$name.' · '.$message,app_url('/admin?section=modules'));continue;}
        try{$module=Modules::installZip((string)$files['tmp_name'][$i],true);queue_webhook('module.installed',['slug'=>$module['slug']??null,'version'=>$module['version']??null]);$message='Проверен, установлен и включён: '.($module['name']??$module['slug']).' '.$module['version'];$coreUpdate=(string)($module['type']??'')==='core_update'||str_starts_with((string)($module['slug']??''),'kovcheg-core-update-');$applyRequired=$applyRequired||$coreUpdate;$results[]=['ok'=>true,'file'=>(string)$name,'message'=>$message,'slug'=>$module['slug']??'','version'=>$module['version']??'','core_update'=>$coreUpdate];admin_notify('success','Модуль установлен',$message,app_url('/admin?section=modules'),Auth::id());}
        catch(Throwable $e){$message=$e->getMessage();$results[]=['ok'=>false,'file'=>(string)$name,'message'=>$message];admin_notify('error','Ошибка установки модуля',(string)$name.' · '.$message,app_url('/admin?section=modules'),Auth::id());}
    }
    if($wantsJson)json_response(['ok'=>!array_filter($results,fn($r)=>empty($r['ok'])),'results'=>$results,'apply_required'=>$applyRequired,'apply_url'=>app_url('/admin?section=modules&apply_updates=1')]);
    $_SESSION['module_results']=$results;redirect('/admin?section=modules');
});
