$router->post('/ajax/channel-comment/send', function(){
    Auth::requireLogin();Csrf::validate();if(!can_do('can_send_messages'))abort(403,'Отправка комментариев запрещена.');
    $chatId=(int)($_POST['chat_id']??0);$rootId=(int)($_POST['root_id']??0);$parentId=(int)($_POST['parent_id']??$rootId);$membership=require_chat_member($chatId);require_unblocked_chat($chatId);$chat=DB::one("SELECT * FROM chats WHERE id=? AND type='channel' AND deleted_at IS NULL",[$chatId]);if(!$chat||empty($chat['comments_enabled']))abort(403,'Комментарии в канале отключены.');
    $root=DB::one('SELECT id FROM messages WHERE id=? AND chat_id=? AND reply_to_id IS NULL AND thread_root_id IS NULL AND deleted_at IS NULL',[$rootId,$chatId]);if(!$root)abort(404,'Публикация не найдена.');
    if($parentId!==$rootId){$parent=DB::one('SELECT id,thread_root_id FROM messages WHERE id=? AND chat_id=? AND deleted_at IS NULL',[$parentId,$chatId]);if(!$parent||(int)($parent['thread_root_id']??0)!==$rootId)abort(422,'Комментарий для ответа не найден.');}
    $body=utf8_substr(trim((string)($_POST['body']??'')),0,5000);$sticker=trim((string)($_POST['sticker_code']??''));$created=[];$eventCursor=0;
    $voice=$_FILES['voice']??null;
    if($voice&&(int)($voice['error']??UPLOAD_ERR_NO_FILE)===UPLOAD_ERR_OK){if(!can_do('can_send_voice'))abort(403,'Голосовые сообщения запрещены.');$max=(int)setting('max_upload_mb','25')*1024*1024;if((int)($voice['size']??0)>$max)abort(422,'Голосовое сообщение слишком большое.');$tmp=(string)$voice['tmp_name'];if($tmp===''||!is_uploaded_file($tmp))abort(422,'Некорректный голосовой файл.');$detected=(new finfo(FILEINFO_MIME_TYPE))->file($tmp)?:'';$voiceTypes=['audio/webm'=>['audio/webm','webm'],'video/webm'=>['audio/webm','webm'],'audio/ogg'=>['audio/ogg','ogg'],'application/ogg'=>['audio/ogg','ogg']];if(!isset($voiceTypes[$detected]))abort(422,'Поддерживаются голосовые файлы WebM и OGG.');[$mime,$ext]=$voiceTypes[$detected];$stored='voice/'.date('Y/m').'/'.bin2hex(random_bytes(16)).'.'.$ext;$dest=BASE_PATH.'/storage/uploads/'.$stored;if(!is_dir(dirname($dest))&&!mkdir(dirname($dest),0755,true)&&!is_dir(dirname($dest)))abort(500,'Не удалось создать папку голосовых сообщений.');if(!move_uploaded_file($tmp,$dest))abort(500,'Не удалось сохранить голосовое сообщение.');$mid=DB::insert("INSERT INTO messages (chat_id,sender_id,type,body,reply_to_id,thread_root_id,created_at) VALUES (?,?,'file','',?,?,CURRENT_TIMESTAMP)",[$chatId,Auth::id(),$parentId,$rootId]);DB::run('INSERT INTO attachments (message_id,original_name,stored_path,mime_type,file_size,created_at) VALUES (?,?,?,?,?,CURRENT_TIMESTAMP)',[$mid,'Голосовой комментарий.'.$ext,$stored,$mime,(int)filesize($dest)]);$created[]=$mid;}
    if($sticker!==''){if(!can_do('can_send_stickers'))abort(403,'Стикеры запрещены.');if(!preg_match('/^sticker:(\\d+)$/',$sticker,$sm)||!DB::one('SELECT s.id FROM stickers s JOIN sticker_packs p ON p.id=s.pack_id WHERE s.id=? AND s.is_active=1 AND p.is_active=1',[(int)$sm[1]]))abort(422,'Стикер недоступен.');$created[]=DB::insert("INSERT INTO messages (chat_id,sender_id,type,sticker_code,reply_to_id,thread_root_id,created_at) VALUES (?,?,'sticker',?,?,?,CURRENT_TIMESTAMP)",[$chatId,Auth::id(),$sticker,$parentId,$rootId]);}
    if($body!=='')$created[]=DB::insert("INSERT INTO messages (chat_id,sender_id,type,body,reply_to_id,thread_root_id,created_at) VALUES (?,?,'text',?,?,?,CURRENT_TIMESTAMP)",[$chatId,Auth::id(),$body,$parentId,$rootId]);
    $files=$_FILES['files']??null;if($files&&is_array($files['name']??null)){if(!can_do('can_send_files'))abort(403,'Файлы запрещены.');$max=(int)setting('max_upload_mb','25')*1024*1024;$allowed=array_filter(array_map('trim',explode(',',(string)setting('allowed_mimes','image/jpeg,image/png,image/webp,audio/webm,audio/ogg,audio/mpeg,video/mp4,application/pdf,text/plain,application/zip'))));for($i=0;$i<count($files['name']);$i++){if((int)$files['error'][$i]!==UPLOAD_ERR_OK||(int)$files['size'][$i]>$max)continue;$tmp=(string)$files['tmp_name'][$i];$name=basename((string)$files['name'][$i]);$mime=(new finfo(FILEINFO_MIME_TYPE))->file($tmp)?:'application/octet-stream';if(!in_array($mime,$allowed,true))continue;$ext=strtolower(pathinfo($name,PATHINFO_EXTENSION));if(preg_match('/^(php|phtml|phar|cgi|pl|sh|exe|js)$/',$ext))continue;if(str_starts_with($mime,'image/')){$img=optimize_uploaded_image($tmp,'chat/'.date('Y/m').'/'.bin2hex(random_bytes(16)),1920,1920,82);$stored=$img['relative'];$mime=$img['mime'];$size=$img['size'];}else{$stored=date('Y/m').'/'.bin2hex(random_bytes(16)).($ext?'.'.$ext:'');$dest=BASE_PATH.'/storage/uploads/'.$stored;if(!is_dir(dirname($dest)))mkdir(dirname($dest),0755,true);if(!move_uploaded_file($tmp,$dest))continue;$size=(int)filesize($dest);} $mid=DB::insert("INSERT INTO messages (chat_id,sender_id,type,body,reply_to_id,thread_root_id,created_at) VALUES (?,?,'file','',?,?,CURRENT_TIMESTAMP)",[$chatId,Auth::id(),$parentId,$rootId]);DB::run('INSERT INTO attachments (message_id,original_name,stored_path,mime_type,file_size,created_at) VALUES (?,?,?,?,?,CURRENT_TIMESTAMP)',[$mid,$name,$stored,$mime,$size]);$created[]=$mid;}}
