});

$router->get('/api/v1/chats/{id}/messages', function($params){ api_auth();$id=(int)$params['id'];require_chat_member($id);$after=(int)($_GET['after_id']??0);$rows=DB::all('SELECT m.*,u.display_name,u.first_name,u.last_name,u.username,u.avatar_path,u.is_verified,u.verification_label,fu.display_name forwarded_from_name,ru.display_name reply_sender_name,rm.body reply_body,a.id attachment_id,a.original_name,a.mime_type,a.file_size FROM messages m JOIN users u ON u.id=m.sender_id LEFT JOIN messages fm ON fm.id=m.forwarded_from_id LEFT JOIN users fu ON fu.id=fm.sender_id LEFT JOIN messages rm ON rm.id=m.reply_to_id LEFT JOIN users ru ON ru.id=rm.sender_id LEFT JOIN attachments a ON a.message_id=m.id WHERE m.chat_id=? AND m.id>? AND m.deleted_at IS NULL ORDER BY m.id ASC LIMIT 100',[$id,$after]);json_response(['ok'=>true,'data'=>array_map('message_payload',$rows)]); });
$router->post('/api/v1/chats/{id}/messages', function($params){ api_auth();$id=(int)$params['id'];$membership=require_chat_member($id);require_unblocked_chat($id);if(!can_do('can_send_messages'))json_response(['ok'=>false,'error'=>'Forbidden'],403);$chatInfo=DB::one('SELECT type FROM chats WHERE id=?',[$id]);if(($chatInfo['type']??'')==='channel'&&!channel_can_post($chatInfo,$membership))json_response(['ok'=>false,'error'=>'Forbidden'],403);$input=json_decode(file_get_contents('php://input'),true)?:$_POST;$body=trim((string)($input['body']??''));if($body==='')json_response(['ok'=>false,'error'=>'body is required'],422);$replyTo=(int)($input['reply_to_id']??0);if($replyTo&&!DB::one('SELECT id FROM messages WHERE id=? AND chat_id=? AND deleted_at IS NULL',[$replyTo,$id]))json_response(['ok'=>false,'error'=>'Invalid reply_to_id'],422);$messageId=DB::insert("INSERT INTO messages (chat_id,sender_id,type,body,reply_to_id,created_at) VALUES (?,?, 'text',?,?,CURRENT_TIMESTAMP)",[$id,Auth::id(),$body,$replyTo?:null]);emit_chat_event($id,'message.created',$messageId);queue_message_push($messageId);$message=message_row($messageId);json_response(['ok'=>true,'data'=>message_payload($message)],201); });



$router->post('/api/v1/messages/{id}/reaction', function($params){ api_auth();$id=(int)$params['id'];$input=json_decode(file_get_contents('php://input'),true)?:$_POST;$emoji=utf8_substr(trim((string)($input['emoji']??'👍')),0,4);$message=DB::one('SELECT chat_id FROM messages WHERE id=? AND deleted_at IS NULL',[$id]);if(!$message)json_response(['ok'=>false,'error'=>'Not found'],404);require_chat_member((int)$message['chat_id']);$exists=DB::one('SELECT id FROM message_reactions WHERE message_id=? AND user_id=? AND emoji=?',[$id,Auth::id(),$emoji]);$exists?DB::run('DELETE FROM message_reactions WHERE id=?',[$exists['id']]):DB::run('INSERT INTO message_reactions (message_id,user_id,emoji,created_at) VALUES (?,?,?,CURRENT_TIMESTAMP)',[$id,Auth::id(),$emoji]);emit_chat_event((int)$message['chat_id'],'message.reaction',$id);json_response(['ok'=>true,'active'=>!$exists]); });
$router->post('/api/v1/messages/{id}/edit', function($params){ api_auth();$id=(int)$params['id'];$message=DB::one('SELECT * FROM messages WHERE id=? AND deleted_at IS NULL',[$id]);if(!$message)json_response(['ok'=>false,'error'=>'Not found'],404);if((int)$message['sender_id']!==Auth::id()&&!Auth::isAdmin())json_response(['ok'=>false,'error'=>'Forbidden'],403);$input=json_decode(file_get_contents('php://input'),true)?:$_POST;$body=trim((string)($input['body']??''));if($body==='')json_response(['ok'=>false,'error'=>'body is required'],422);DB::run('UPDATE messages SET body=?,edited_at=CURRENT_TIMESTAMP WHERE id=?',[$body,$id]);emit_chat_event((int)$message['chat_id'],'message.updated',$id);json_response(['ok'=>true,'data'=>message_payload(message_row($id))]); });
