$router->post('/api/v1/messages/{id}/forward', function($params){ api_auth();$id=(int)$params['id'];$source=message_row($id);if(!$source)json_response(['ok'=>false,'error'=>'Not found'],404);require_chat_member((int)$source['chat_id']);$input=json_decode(file_get_contents('php://input'),true)?:$_POST;$target=(int)($input['user_id']??0);if(!$target||$target===Auth::id())json_response(['ok'=>false,'error'=>'user_id is required'],422);if(!are_colleagues(Auth::id(),$target))json_response(['ok'=>false,'error'=>'Target must be a colleague'],403);$chatId=direct_chat_with($target);$newId=DB::insert('INSERT INTO messages (chat_id,sender_id,type,body,sticker_code,forwarded_from_id,created_at) VALUES (?,?,?,?,?,?,CURRENT_TIMESTAMP)',[$chatId,Auth::id(),$source['type'],$source['body'],$source['sticker_code'],$id]);if(!empty($source['attachment_id']))DB::run('INSERT INTO attachments (message_id,original_name,stored_path,mime_type,file_size,created_at) VALUES (?,?,?,?,?,CURRENT_TIMESTAMP)',[$newId,$source['original_name'],$source['stored_path'],$source['mime_type'],$source['file_size']]);emit_chat_event($chatId,'message.created',$newId);queue_message_push($newId);json_response(['ok'=>true,'data'=>['message_id'=>$newId,'chat_id'=>$chatId]],201); });
